import tkinter as tk
from tkinter import filedialog

@app.route('/api/browse-folder', methods=['POST'])
def browse_folder():
    root = tk.Tk()
    root.withdraw()
    root.attributes('-topmost', True)
    folder = filedialog.askdirectory()
    root.destroy()
    return jsonify({'folder': folder or ''})

def progress_hook(d):
    if d['status'] == 'downloading':
        pct = d.get('_percent_str', '0%').strip()
        speed = d.get('_speed_str', '')
        eta = d.get('_eta_str', '')
        with lock:
            progress_store[task_id] = {
                'status': 'downloading',
                'percent': float(pct.rstrip('%')),
                'speed': speed, 'eta': eta
            }
opts['progress_hooks'] = [progress_hook]

subtitle_url_store = {}  # video_id -> {urls: {lang: {ext: url}}}
subtitle_cache = {}      # (video_id, lang, fmt) -> {content, time}
_subtitle_429_until = 0  # Global cooldown timestamp

def _get_cached_subtitle(url, lang, fmt, video_id):
    key = (video_id, lang, fmt)
    if key in subtitle_cache:
        cached = subtitle_cache[key]
        if time.time() - cached['time'] < 1800:  # 30min TTL
            return cached['content']
    # Fetch via HTTP (NOT yt-dlp)
    content = _fetch_subtitle_url(url)
    if content:
        subtitle_cache[key] = {'content': content, 'time': time.time()}
    return content

TEMP_DIR = os.path.join(os.path.dirname(__file__), '.tmp')
os.makedirs(TEMP_DIR, exist_ok=True)

def cleanup_old_temps():
    cutoff = time.time() - 7200  # 2 hours
    for f in os.listdir(TEMP_DIR):
        path = os.path.join(TEMP_DIR, f)
        if os.path.getmtime(path) < cutoff:
            try:
                os.remove(path)
            except OSError:
                pass

@app.route('/api/default-save-dir')
def default_save_dir():
    default = os.path.join(os.path.expanduser('~'), 'Downloads', 'MyApp')
    os.makedirs(default, exist_ok=True)
    return jsonify({'path': default})

import subprocess

@app.route('/api/open-folder', methods=['POST'])
def open_folder():
    path = request.get_json().get('path', '')
    path = os.path.normpath(path)
    if os.path.isdir(path):
        subprocess.Popen(['explorer', path])
        return jsonify({'ok': True})
    return jsonify({'error': 'Invalid path'}), 400

from flask import send_file

@app.route('/api/file/<task_id>')
def serve_file(task_id):
    with lock:
        filepath = file_store.get(task_id)
    if not filepath or not os.path.exists(filepath):
        return jsonify({'error': 'File not found'}), 404
    return send_file(filepath, as_attachment=True,
        download_name=os.path.basename(filepath))

import shutil
import glob

def find_ffmpeg():
    # Check PATH first
    if shutil.which('ffmpeg'):
        return os.path.dirname(shutil.which('ffmpeg'))
    # Check WinGet install path
    winget_paths = glob.glob(r'C:\Users\*\AppData\Local\Microsoft\WinGet\Packages\*ffmpeg*\ffmpeg*.exe')
    if winget_paths:
        return os.path.dirname(winget_paths[0])
    return None

FFMPEG_DIR = find_ffmpeg()
